UPDATE stock_minute_bar
SET bar_end_time = #{barEndTime}, open_price = #{openPrice}, high_price = #{highPrice},
    low_price = #{lowPrice}, close_price = #{closePrice}, volume = #{volume}, amount = #{amount},
